18	/// Shared handle passed to the control listener and polled by tray/UI.
19	///
20	/// All fields are cheap to clone (Arc-wrapped).
21	#[derive(Clone)]
22	pub struct DaemonHandle {
23	    /// Macro dispatcher shared with the pipeline; used to push profile updates.
24	    pub dispatcher: Arc<Dispatcher>,
25	    /// Set true to suppress audio processing. The pipeline thread checks this
26	    /// on each frame and skips wake/VAD/STT while muted.
27	    pub muted: Arc<AtomicBool>,
28	    /// Name of the currently active profile, updated on every SwitchProfile.
29	    pub active_profile: Arc<RwLock<Option<String>>>,
30	    /// Set true while the wake-word listen window is open (written by coordinator).
31	    pub listening: Arc<AtomicBool>,
32	    /// Set true while PTT is held (written by coordinator).
33	    pub recording: Arc<AtomicBool>,
34	    /// Channel to the running pipeline coordinator for live runtime changes.
35	    /// `None` when the pipeline is not running (e.g. during unit tests).
36	    pub runtime_cmd_tx: Option<Arc<std::sync::mpsc::Sender<RuntimeCommand>>>,
37	}
38	
39	impl DaemonHandle {
40	    /// Create a new handle wrapping the given dispatcher with all state flags initialised to false/None.
41	    pub fn new(dispatcher: Arc<Dispatcher>) -> Self {
42	        Self {
43	            dispatcher,
44	            muted: Arc::new(AtomicBool::new(false)),
45	            active_profile: Arc::new(RwLock::new(None)),
46	            listening: Arc::new(AtomicBool::new(false)),
47	            recording: Arc::new(AtomicBool::new(false)),
48	            runtime_cmd_tx: None,
49	        }
50	    }
51	
52	    /// Attach the runtime command sender produced by `spawn_pipeline`.
53	    pub fn with_runtime_tx(mut self, tx: std::sync::mpsc::Sender<RuntimeCommand>) -> Self {
54	        self.runtime_cmd_tx = Some(Arc::new(tx));
55	        self
56	    }
57	
58	    /// Send a [`RuntimeCommand`] to the pipeline coordinator.
59	    ///
60	    /// Returns `ControlResponse::Ok` on success or
61	    /// `ControlResponse::Error { message }` when the pipeline is not running.
62	    fn send_runtime_cmd(&self, cmd: RuntimeCommand) -> ControlResponse {
63	        match &self.runtime_cmd_tx {
64	            Some(tx) => match tx.send(cmd) {
65	                Ok(()) => ControlResponse::Ok,
66	                Err(_) => ControlResponse::Error { message: "pipeline not running".into() },
67	            },
68	            None => ControlResponse::Error { message: "pipeline not running".into() },
69	        }
70	    }
71	
72	    /// Derive the current [`DaemonState`] from the atomic flags, in priority order: Muted > Recording > Listening > Idle.
73	    pub fn state(&self) -> DaemonState {
74	        if self.muted.load(Ordering::Relaxed) {
75	            DaemonState::Muted
76	        } else if self.recording.load(Ordering::Relaxed) {
77	            DaemonState::Recording
78	        } else if self.listening.load(Ordering::Relaxed) {
79	            DaemonState::Listening
80	        } else {
81	            DaemonState::Idle
82	        }
83	    }
84	
85	    /// Build a full [`DaemonStatus`] snapshot (state + active profile + macro count) for Status queries.
86	    pub fn status(&self) -> DaemonStatus {
87	        let macro_count = self.dispatcher.macro_count();
88	        DaemonStatus {
89	            state: self.state(),
90	            active_profile: self.active_profile.read().unwrap().clone(),
91	            macro_count,
92	        }
93	    }
94	}
