96	/// Spawn the control channel listener on a Tokio task.
97	///
98	/// Listens on a Unix Domain Socket for commands from the CLI.
99	pub async fn spawn_control_listener(handle: DaemonHandle) -> Result<()> {
100	    let socket_path = get_socket_path()?;
101	
102	    // Clean up existing socket file if it exists
103	    if socket_path.exists() {
104	        std::fs::remove_file(&socket_path)
105	            .with_context(|| format!("Failed to remove existing socket: {}", socket_path.display()))?;
106	    }
107	
108	    let listener = UnixListener::bind(&socket_path)
109	        .with_context(|| format!("Failed to bind to UDS socket: {}", socket_path.display()))?;
110	
111	    // Set permissions to 0600 (user only)
112	    #[cfg(unix)]
113	    {
114	        use std::os::unix::fs::PermissionsExt;
115	        std::fs::set_permissions(&socket_path, std::fs::Permissions::from_mode(0o600))?;
116	    }
117	
118	    tracing::info!("Control channel listening on: {}", socket_path.display());
119	
120	    tokio::spawn(async move {
121	        loop {
122	            match listener.accept().await {
123	                Ok((mut stream, _)) => {
124	                    let h = handle.clone();
125	                    tokio::spawn(async move {
126	                        let (reader, mut writer) = stream.split();
127	                        let mut reader = BufReader::new(reader);
128	                        let mut line = String::new();
129	
130	                        if let Ok(n) = reader.read_line(&mut line).await {
131	                            if n == 0 { return; }
132	
133	                            let response = match serde_json::from_str::<ControlRequest>(&line) {
134	                                Ok(req) => {
135	                                    tracing::debug!("Control request: {:?}", req);
136	                                    match req {
137	                                        ControlRequest::Ping => ControlResponse::Pong,
138	                                        ControlRequest::Status => {
139	                                            ControlResponse::StatusData(h.status())
140	                                        }
141	                                        ControlRequest::Mute => {
142	                                            h.muted.store(true, Ordering::Relaxed);
143	                                            tracing::info!("Daemon muted via control socket");
144	                                            ControlResponse::Ok
145	                                        }
146	                                        ControlRequest::Unmute => {
147	                                            h.muted.store(false, Ordering::Relaxed);
148	                                            tracing::info!("Daemon unmuted via control socket");
149	                                            ControlResponse::Ok
150	                                        }
151	                                        ControlRequest::SwitchProfile { name } => {
152	                                            match tokio::task::block_in_place(|| {
153	                                                handle_switch_profile(&name, &h)
154	                                            }) {
155	                                                Ok(_) => ControlResponse::Ok,
156	                                                Err(e) => ControlResponse::Error { message: e.to_string() },
157	                                            }
158	                                        }
159	                                        ControlRequest::Shutdown => {
160	                                            // TODO: wire to CancellationToken in a future slice
161	                                            ControlResponse::Ok
162	                                        }
163	                                        ControlRequest::SetMode { mode } => {
164	                                            h.send_runtime_cmd(RuntimeCommand::SetMode(mode))
165	                                        }
166	                                        ControlRequest::SetThreshold { threshold } => {
167	                                            h.send_runtime_cmd(RuntimeCommand::SetThreshold(threshold))
168	                                        }
169	                                        ControlRequest::SetInputDevice { device } => {
170	                                            tracing::info!("SetInputDevice received; requires daemon restart (S01 note)");
171	                                            h.send_runtime_cmd(RuntimeCommand::SetInputDevice(device))
172	                                        }
173	                                        ControlRequest::SetPttBinding { key } => {
174	                                            tracing::info!("SetPttBinding received; requires daemon restart (S01 note)");
175	                                            h.send_runtime_cmd(RuntimeCommand::SetPttBinding(key))
176	                                        }
177	                                        ControlRequest::ReloadConfig => {
178	                                            h.send_runtime_cmd(RuntimeCommand::ReloadConfig)
179	                                        }
180	                                        _ => ControlResponse::Error { message: "Not yet implemented".into() },
181	                                    }
182	                                }
183	                                Err(e) => ControlResponse::Error { message: format!("Invalid JSON: {e}") },
184	                            };
185	
186	                            if let Ok(resp_json) = serde_json::to_string(&response) {
187	                                let _ = writer.write_all(resp_json.as_bytes()).await;
188	                                let _ = writer.write_all(b"\n").await;
189	                            }
190	                        }
191	                    });
192	                }
193	                Err(e) => {
194	                    tracing::error!("Control listener accept error: {e}");
195	                }
196	            }
197	        }
198	    });
199	
200	    Ok(())
201	}
